#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <time.h>
#include <unistd.h>

#define DEFAULT_SIZE 1.0
#define CUTOFF 0.01
#define MIN_R 0.0001
#define DT 0.0005
#define DENSITY 0.0005
#define MASS 0.01
#define STEPS 1000

typedef struct {
    double x, y;
    double vx, vy;
    double fx, fy;
} particle_t;

typedef struct {
    int *particles;
    int count;
    int capacity;
} bin_t;

void init_particle(particle_t *p, double size) {
    p->x = drand48() * size;
    p->y = drand48() * size;
    p->vx = drand48() - 0.5;
    p->vy = drand48() - 0.5;
    p->fx = p->fy = 0.0;
}

void apply_force(particle_t *p1, particle_t *p2) {
    double dx = p1->x - p2->x;
    double dy = p1->y - p2->y;
    double r2 = dx * dx + dy * dy;

    if (r2 > CUTOFF * CUTOFF) return;
    if (r2 < MIN_R * MIN_R) r2 = MIN_R * MIN_R;

    double r = sqrt(r2);
    double coef = (1 - CUTOFF / r) / r2 / MASS;

    p1->fx += coef * dx;
    p1->fy += coef * dy;
}

void move_particle(particle_t *p, double size) {
    p->vx += p->fx * DT;
    p->vy += p->fy * DT;
    p->x += p->vx * DT;
    p->y += p->vy * DT;

    // Handle boundaries
    while (p->x < 0 || p->x > size) {
        p->x = p->x < 0 ? -p->x : 2 * size - p->x;
        p->vx = -p->vx;
    }
    while (p->y < 0 || p->y > size) {
        p->y = p->y < 0 ? -p->y : 2 * size - p->y;
        p->vy = -p->vy;
    }

    p->fx = p->fy = 0.0;
}

void add_to_bin(bin_t *bin, int particle_id) {
    if (bin->count >= bin->capacity) {
        bin->capacity = bin->capacity ? bin->capacity * 2 : 4;
        bin->particles = realloc(bin->particles, bin->capacity * sizeof(int));
    }
    bin->particles[bin->count++] = particle_id;
}

void simulate(particle_t *particles, int n, double size) {
    double bin_size = CUTOFF;
    int nbins = (int)(size / bin_size) + 1;
    bin_t *bins = calloc(nbins * nbins, sizeof(bin_t));

    for (int step = 0; step < STEPS; step++) {
        // Clear bins
        for (int i = 0; i < nbins * nbins; i++) {
            bins[i].count = 0;
        }

        // Assign particles to bins
        for (int i = 0; i < n; i++) {
            int bx = (int)(particles[i].x / bin_size);
            int by = (int)(particles[i].y / bin_size);
            if (bx >= 0 && bx < nbins && by >= 0 && by < nbins) {
                add_to_bin(&bins[by * nbins + bx], i);
            }
        }

        // Compute forces
        for (int by = 0; by < nbins; by++) {
            for (int bx = 0; bx < nbins; bx++) {
                bin_t *current_bin = &bins[by * nbins + bx];

                // Interactions within the bin
                for (int i = 0; i < current_bin->count; i++) {
                    for (int j = i + 1; j < current_bin->count; j++) {
                        apply_force(&particles[current_bin->particles[i]], 
                                  &particles[current_bin->particles[j]]);
                        apply_force(&particles[current_bin->particles[j]], 
                                  &particles[current_bin->particles[i]]);
                    }
                }

                // Interactions with neighboring bins
                for (int dy = -1; dy <= 1; dy++) {
                    for (int dx = -1; dx <= 1; dx++) {
                        if (dx == 0 && dy == 0) continue;
                        int nx = bx + dx, ny = by + dy;
                        if (nx >= 0 && nx < nbins && ny >= 0 && ny < nbins) {
                            bin_t *neighbor_bin = &bins[ny * nbins + nx];
                            for (int i = 0; i < current_bin->count; i++) {
                                for (int j = 0; j < neighbor_bin->count; j++) {
                                    apply_force(&particles[current_bin->particles[i]], 
                                              &particles[neighbor_bin->particles[j]]);
                                }
                            }
                        }
                    }
                }
            }
        }

        // Move particles
        for (int i = 0; i < n; i++) {
            move_particle(&particles[i], size);
        }
    }

    // Cleanup
    for (int i = 0; i < nbins * nbins; i++) {
        free(bins[i].particles);
    }
    free(bins);
}

void compute_metrics(particle_t *particles, int n, double *absmin, double *absavg) {
    double min_dist = 1e9;
    double sum_dist = 0.0;
    int count = 0;

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            double dx = particles[i].x - particles[j].x;
            double dy = particles[i].y - particles[j].y;
            double dist = sqrt(dx * dx + dy * dy) / CUTOFF;

            if (dist < min_dist) min_dist = dist;
            sum_dist += dist;
            count++;
        }
    }

    *absmin = min_dist;
    *absavg = count > 0 ? sum_dist / count : 0.0;
}

int main(int argc, char **argv) {
    int n = 0;
    char *output_file = NULL;
    char *summary_file = NULL;

    // Parse command line arguments
    int opt;
    while ((opt = getopt(argc, argv, "n:o:s:")) != -1) {
        switch (opt) {
            case 'n':
                n = atoi(optarg);
                break;
            case 'o':
                output_file = optarg;
                break;
            case 's':
                summary_file = optarg;
                break;
            default:
                fprintf(stderr, "Usage: %s -n <particles> [-o output_file] [-s summary_file]\n", argv[0]);
                return 1;
        }
    }

    if (n <= 0) {
        fprintf(stderr, "Number of particles must be positive\n");
        return 1;
    }

    srand48(12345); // Fixed seed for reproducibility

    double size = sqrt(DENSITY * n);
    particle_t *particles = malloc(n * sizeof(particle_t));

    // Initialize particles
    for (int i = 0; i < n; i++) {
        init_particle(&particles[i], size);
    }

    // Record initial positions for movement check
    double *initial_x = malloc(n * sizeof(double));
    double *initial_y = malloc(n * sizeof(double));
    for (int i = 0; i < n; i++) {
        initial_x[i] = particles[i].x;
        initial_y[i] = particles[i].y;
    }

    // Run simulation
    clock_t start = clock();
    simulate(particles, n, size);
    clock_t end = clock();
    double simulation_time = ((double)(end - start)) / CLOCKS_PER_SEC;

    // Check particle movement
    int moved_count = 0;
    for (int i = 0; i < n; i++) {
        double dx = particles[i].x - initial_x[i];
        double dy = particles[i].y - initial_y[i];
        if (sqrt(dx * dx + dy * dy) > 0.0001) {
            moved_count++;
        }
    }

    // Compute metrics
    double absmin, absavg;
    compute_metrics(particles, n, &absmin, &absavg);

    // Print results
    printf("n = %d, simulation time = %g seconds\n", n, simulation_time);
    printf("absmin = %g\n", absmin);
    printf("absavg = %g\n", absavg);

    // Write output file
    const char *out_filename = output_file ? output_file : "/app/serial.txt";
    FILE *outf = fopen(out_filename, "w");
    if (outf) {
        fprintf(outf, "%d %g\n", n, size);
        for (int i = 0; i < n; i++) {
            fprintf(outf, "%g %g\n", particles[i].x, particles[i].y);
        }
        fclose(outf);
    }

    // Write summary file
    const char *sum_filename = summary_file ? summary_file : "/app/serial_summary.txt";
    FILE *sumf = fopen(sum_filename, "w");
    if (sumf) {
        fprintf(sumf, "%d %g\n", n, simulation_time);
        fclose(sumf);
    }

    free(particles);
    free(initial_x);
    free(initial_y);

    return 0;
}
EOF
