        #pragma omp parallel for
        for (int i = 0; i < n; i++) {
            move_particle(&particles[i], size);
        }
    }

    // Cleanup
    for (int i = 0; i < nbins * nbins; i++) {
        free(bins[i].particles);
    }
    free(bins);
}

void compute_metrics(particle_t *particles, int n, double *absmin, double *absavg) {
    double min_dist = 1e9;
    double sum_dist = 0.0;
    int count = 0;

    #pragma omp parallel
    {
        double local_min = 1e9;
        double local_sum = 0.0;
        int local_count = 0;

        #pragma omp for
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                double dx = particles[i].x - particles[j].x;
                double dy = particles[i].y - particles[j].y;
                double dist = sqrt(dx * dx + dy * dy) / CUTOFF;

                if (dist < local_min) local_min = dist;
                local_sum += dist;
                local_count++;
            }
        }

        #pragma omp critical
        {
            if (local_min < min_dist) min_dist = local_min;
            sum_dist += local_sum;
            count += local_count;
        }
    }

    *absmin = min_dist;
    *absavg = count > 0 ? sum_dist / count : 0.0;
}

int main(int argc, char **argv) {
    int n = 0;
    int num_threads = 0;
    char *output_file = NULL;
    char *summary_file = NULL;

    // Parse command line arguments
    int opt;
    while ((opt = getopt(argc, argv, "n:p:o:s:")) != -1) {
        switch (opt) {
            case 'n':
                n = atoi(optarg);
                break;
            case 'p':
                num_threads = atoi(optarg);
                break;
            case 'o':
                output_file = optarg;
                break;
            case 's':
                summary_file = optarg;
                break;
            default:
                fprintf(stderr, "Usage: %s -n <particles> [-p threads] [-o output_file] [-s summary_file]\n", argv[0]);
                return 1;
        }
    }

    if (n <= 0) {
        fprintf(stderr, "Number of particles must be positive\n");
        return 1;
    }

    if (num_threads > 0) {
        omp_set_num_threads(num_threads);
    }

    srand48(12345); // Fixed seed for reproducibility

    double size = sqrt(DENSITY * n);
    particle_t *particles = malloc(n * sizeof(particle_t));

    // Initialize particles
    for (int i = 0; i < n; i++) {
        init_particle(&particles[i], size);
    }

    // Record initial positions for movement check
    double *initial_x = malloc(n * sizeof(double));
    double *initial_y = malloc(n * sizeof(double));
    for (int i = 0; i < n; i++) {
        initial_x[i] = particles[i].x;
        initial_y[i] = particles[i].y;
    }

    // Run simulation
    double start_time = omp_get_wtime();
    simulate(particles, n, size);
    double end_time = omp_get_wtime();
    double simulation_time = end_time - start_time;

    int actual_threads = omp_get_max_threads();

    // Check particle movement
    int moved_count = 0;
    for (int i = 0; i < n; i++) {
        double dx = particles[i].x - initial_x[i];
        double dy = particles[i].y - initial_y[i];
        if (sqrt(dx * dx + dy * dy) > 0.0001) {
            moved_count++;
        }
    }

    // Compute metrics
    double absmin, absavg;
    compute_metrics(particles, n, &absmin, &absavg);

    // Print results
    printf("n = %d, threads = %d, simulation time = %g seconds\n", n, actual_threads, simulation_time);
    printf("absmin = %g\n", absmin);
    printf("absavg = %g\n", absavg);

    // Write output file
    const char *out_filename = output_file ? output_file : "/app/openmp.txt";
    FILE *outf = fopen(out_filename, "w");
    if (outf) {
        fprintf(outf, "%d %g\n", n, size);
        for (int i = 0; i < n; i++) {
            fprintf(outf, "%g %g\n", particles[i].x, particles[i].y);
        }
        fclose(outf);
    }

    // Write summary file
    const char *sum_filename = summary_file ? summary_file : "/app/openmp_summary.txt";
    FILE *sumf = fopen(sum_filename, "w");
    if (sumf) {
        fprintf(sumf, "%d %d %g\n", n, actual_threads, simulation_time);
        fclose(sumf);
    }

    free(particles);
    free(initial_x);
    free(initial_y);

    return 0;
}
